router = APIRouter(tags=["health"])


class HealthResponse(BaseModel):
    status: str
    service: str
    db: str | None = None


@router.get("/healthz", response_model=HealthResponse)
async def healthz(db: AsyncSession = Depends(get_db_session)) -> HealthResponse | JSONResponse:
    """Liveness probe — confirms the service process and database are reachable."""
    try:
        await db.execute(text("SELECT 1"))
        return HealthResponse(status="ok", service="backtrace-agent", db="ok")
    except Exception:
        return JSONResponse(
            status_code=503,
            content={"status": "degraded", "service": "backtrace-agent", "db": "down"},
        )

